<template><ion-page><AppHeader /><ion-content class="vivid-page"><div class="page-shell dashboard"><h1>Olá, {{ firstName }}</h1><p>Bem-vindo de volta ao painel de controle.</p><section class="metrics"><article class="vivid-card"><span class="tech-label">Itens em estoque</span><strong>{{ stats.totalQuantity }}</strong></article><article class="vivid-card"><span class="tech-label">Valor de custo</span><strong>{{ money(stats.totalCostValue) }}</strong></article><article class="vivid-card"><span class="tech-label">Anúncios (Anunc/Não)</span><strong>{{ stats.totalListed }}/{{ stats.totalUnlisted }}</strong></article></section><section><h2>Fotos Recentes dos Produtos</h2><div class="recent"><article v-for="item in inventory.items.slice(0,2)" :key="item.id" class="vivid-card"><img :src="getImageUrl(item.images?.[0])" /><h3>{{ item.name }}</h3><p class="tech-label">Estoque: {{ item.quantity }}</p></article></div></section><section class="vivid-card quick"><h2>Ações Rápidas</h2><div><button @click="$router.push('/movement?type=IN')">Entrada</button><button @click="$router.push('/movement?type=OUT')">Saída</button><button @click="$router.push('/scanner')">Scan Barcode</button><button @click="$router.push('/inventory')">Catálogo</button></div></section><button v-if="inventory.movementsQueue.length" class="sync" @click="inventory.loadState">{{ inventory.movementsQueue.length }} movimentações pendentes</button></div><BottomNav /></ion-content></ion-page></template>
<script setup lang="ts">import { computed, ref } from 'vue';import { IonPage,IonContent,onIonViewWillEnter } from '@ionic/vue';import AppHeader from '@/components/AppHeader.vue';import BottomNav from '@/components/BottomNav.vue';import { useInventoryStore } from '@/stores/inventory';import { useAuthStore } from '@/stores/auth';import { getImageUrl } from '@/utils/url';import api from '@/services/api';const inventory=useInventoryStore(),auth=useAuthStore();const firstName=computed(()=>auth.user?.name?.split(' ')[0]||'Operador');const stats = ref({  totalProducts: 0,  totalQuantity: 0,  totalCostValue: 0,  totalListed: 0,  totalUnlisted: 0,});const fetchStats = async () => {  try {    const { data } = await api.get('/dashboard/stats');    stats.value = data;  } catch (err) {    console.error('Failed to fetch dashboard stats:', err);  }};const money=(v:number)=>v.toLocaleString('pt-BR',{style:'currency',currency:'BRL',maximumFractionDigits:0});onIonViewWillEnter(()=>{  inventory.fetchItems();  fetchStats();});</script>
<style scoped>.dashboard>h1{margin:26px 0 2px}.dashboard>p{color:var(--vivid-muted);margin-top:0}.metrics{display:grid;gap:14px;margin:30px 0}.metrics article{padding:18px;min-height:122px;background:linear-gradient(135deg,#2c192c,var(--vivid-surface))}.metrics strong{display:block;font-size:26px;margin-top:28px}.recent{display:grid;grid-template-columns:1fr 1fr;gap:14px}.recent article{overflow:hidden}.recent img{width:100%;height:135px;object-fit:cover}.recent h3,.recent p{padding:0 12px}.quick{padding:18px;margin-top:28px}.quick div{display:grid;grid-template-columns:1fr 1fr;gap:12px}.quick button{height:70px;border:0;border-radius:12px;background:var(--vivid-surface-high);color:var(--vivid-text)}.quick button:first-child{background:var(--vivid-primary)}.sync{width:100%;margin-top:18px;padding:14px;border:0;border-radius:12px;background:#684179;color:white}</style>
